      { id: 50, text: "Sắp xếp thứ tự các hành động khi muốn dùng máy tính để học tập:", options: ["Ngồi đúng tư thế", "Bật công tắc nguồn", "Chờ máy khởi động", "Mở phần mềm học tập"], correctAnswer: ["Ngồi đúng tư thế", "Bật công tắc nguồn", "Chờ máy khởi động", "Mở phần mềm học tập"], explanation: "Chuẩn bị kỹ trước khi bắt đầu học.", difficulty: "Medium", topic: "Máy tính & Em", type: "ORDERING" }
